      const db = getDb();
      const user = db.users.find(u => u.email === email);

      if (user) {
        onLogin(user);
        navigate(user.role === UserRole.ADMIN ? '/admin' : '/projects');
      } else {
        setError('Invalid credentials. Hint: Use admin@ngo.org or john@volunteer.com');
