                           <FileText className="h-5 w-5" />
                        </div>
                      </div>
                      <p className="mt-2 text-[9px] text-slate-400 font-bold uppercase tracking-widest italic">Vendosni linkun e dokumentit PDF të ngarkuar diku tjetër.</p>
                   </div>
                )}
                <button 
                  onClick={handleAddNews}
                  className={`w-full py-5 text-white rounded-2xl font-black uppercase text-xs tracking-[0.2em] shadow-xl hover:bg-brand-dark transition-all ${
                    newNews.category === 'Raportet' ? 'bg-brand-cyan' : 'bg-brand-orange'
                  }`}
                >
                   Ruaj {newNews.category === 'Raportet' ? 'Raportin' : 'Lajmin'}
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

