import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { getDb } from '../services/mockDb';
import { NewsItem } from '../types';
import { Calendar, Tag, ArrowRight, Newspaper, Tv, FileText, Download, ExternalLink } from 'lucide-react';

const News: React.FC = () => {
  const { category } = useParams<{ category: string }>();
  const [news, setNews] = useState<NewsItem[]>([]);

  useEffect(() => {
    const db = getDb();
    let items = db.news || [];

    if (category) {
      const mapping: Record<string, string> = {
        'latest': 'Lajmet e fundit',
        'media': 'Media',
        'reports': 'Raportet'
      };
      const dbCategory = mapping[category];
      if (dbCategory) {
        items = items.filter(n => n.category === dbCategory);
      }
    }
    setNews(items);
  }, [category]);

  const getTitle = () => {
    switch (category) {
      case 'media': return 'Media & Intervista';
      case 'latest': return 'Lajmet e Fundit';
      case 'reports': return 'Raportet & Publikimet';
      default: return 'Të gjitha Lajmet';
    }
  };

  const getIcon = (cat: string) => {
    if (cat === 'Media') return <Tv className="h-5 w-5 text-brand-orange" />;
    if (cat === 'Raportet') return <FileText className="h-5 w-5 text-brand-cyan" />;
    return <Newspaper className="h-5 w-5 text-brand-pink" />;
  };

  return (
    <div className="py-20 px-6 bg-slate-50 min-h-screen">
      <div className="max-w-5xl mx-auto">
        <div className="mb-16">
          <h1 className="text-5xl font-black text-brand-dark uppercase tracking-tighter mb-4">{getTitle()}</h1>
          <div className="h-1.5 w-24 bg-brand-pink rounded-full"></div>
        </div>

        {news.length === 0 ? (
          <div className="bg-white p-20 rounded-[2.5rem] text-center border border-slate-100">
            <p className="text-slate-400 font-bold uppercase tracking-widest">Nuk u gjet asnjë lajm në këtë kategori.</p>
          </div>
        ) : (
          <div className="space-y-8">
            {news.map((item) => (
              <div key={item.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm hover:shadow-xl transition-all border border-slate-100 flex flex-col md:flex-row md:items-center gap-8 group">
                <div className="w-16 h-16 bg-slate-50 rounded-2xl flex items-center justify-center flex-shrink-0 group-hover:bg-brand-pink group-hover:text-white transition-colors">
                  {getIcon(item.category)}
                </div>
                <div className="flex-grow">
                  <div className="flex flex-wrap items-center gap-4 mb-3">
                    <span className="flex items-center text-[10px] font-black text-slate-400 uppercase tracking-widest">
                      <Calendar className="h-3 w-3 mr-1" />
                      {item.datePosted}
                    </span>
                    <span className="px-3 py-1 bg-slate-50 text-[10px] font-black text-slate-500 uppercase tracking-widest rounded-full">
                      {item.category}
                    </span>
                  </div>
                  <h3 className="text-2xl font-black text-brand-dark uppercase leading-tight mb-2 group-hover:text-brand-pink transition-colors">
                    {item.title}
                  </h3>
                  <p className="text-slate-500 font-medium line-clamp-2 leading-relaxed">
                    {item.content}
                  </p>

                  <div className="flex gap-4 mt-6">
                    {item.category === 'Raportet' && item.fileUrl && (
                      <a 
                        href={item.fileUrl} 
                        download={item.title.replace(/\s+/g, '_') + ".pdf"}
                        className="flex items-center space-x-2 bg-brand-cyan/10 text-brand-cyan px-5 py-2.5 rounded-full font-black uppercase text-[10px] tracking-widest hover:bg-brand-cyan hover:text-white transition-all"
                      >
                        <Download className="h-3.5 w-3.5" />
                        <span>Shkarko PDF</span>
                      </a>
                    )}

                    {item.category === 'Media' && item.fileUrl && (
                      <a 
                        href={item.fileUrl} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center space-x-2 bg-brand-orange/10 text-brand-orange px-5 py-2.5 rounded-full font-black uppercase text-[10px] tracking-widest hover:bg-brand-orange hover:text-white transition-all"
                      >
                        <ExternalLink className="h-3.5 w-3.5" />
                        <span>Shiko Burimin</span>
                      </a>
                    )}
                  </div>
                </div>
                {(!item.fileUrl || item.category === 'Lajmet e fundit') && (
                  <button className="flex items-center justify-center w-12 h-12 bg-slate-50 rounded-full group-hover:bg-brand-dark group-hover:text-white transition-all">
                    <ArrowRight className="h-5 w-5" />
                  </button>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default News;

import React, { useState, useEffect, useRef } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell,
  PieChart, Pie, Legend
} from 'recharts';
import { 
  LayoutDashboard, FolderKanban, Users, Calendar, Megaphone, 
  Plus, Edit2, Trash2, Check, X, Sparkles, FileText, Newspaper, Tv, Clock, Download, ExternalLink, Upload, Link as LinkIcon, Briefcase, Camera, Facebook, Instagram, Linkedin
} from 'lucide-react';
import { getDb, saveDb } from '../services/mockDb';
import { Project, ApplicationStatus, ProjectStatus, NewsItem, StaffMember } from '../types';
import { generateProjectPitch } from '../services/gemini';

const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'projects' | 'applications' | 'news' | 'reports' | 'staff'>('overview');
  const [db, setDb] = useState(getDb());
  const [showProjectModal, setShowProjectModal] = useState(false);
  const [showNewsModal, setShowNewsModal] = useState(false);
  const [showStaffModal, setShowStaffModal] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [isUploading, setIsUploading] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Form States
  const [newProject, setNewProject] = useState({
    title: '',
    description: '',
    startDate: '',
    endDate: '',
    keywords: '',
    image: 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?auto=format&fit=crop&q=80&w=800'
  });

  const [newNews, setNewNews] = useState({
    title: '',
    content: '',
    category: 'Lajmet e fundit',
    datePosted: new Date().toISOString().split('T')[0],
    fileUrl: '',
    fileName: ''
  });

  const [newStaff, setNewStaff] = useState({
    name: '',
    role: '',
    bio: '',
    image: 'https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?auto=format&fit=crop&q=80&w=400',
    socials: { facebook: '', instagram: '', linkedin: '' }
  });

  useEffect(() => {
    setDb(getDb());
  }, []);

  const stats = [
    { label: 'Projekte Totale', value: db.projects.length, icon: FolderKanban, color: 'bg-brand-pink' },
    { label: 'Vullnetarë', value: db.users.filter(u => u.role === 'VOLUNTEER').length, icon: Users, color: 'bg-brand-cyan' },
    { label: 'Staff Aktiv', value: db.staff.length, icon: Briefcase, color: 'bg-brand-blue' },
    { label: 'Lajme & Raporte', value: db.news.length, icon: Megaphone, color: 'bg-brand-lime' },
  ];

  const projectStats = db.projects.map(p => ({ name: p.title.substring(0, 10) + '...', volunteers: p.volunteerCount }));
  const appStatusData = [
    { name: 'Aprovuar', value: db.applications.filter(a => a.status === ApplicationStatus.APPROVED).length },
    { name: 'Pritje', value: db.applications.filter(a => a.status === ApplicationStatus.PENDING).length },
    { name: 'Refuzuar', value: db.applications.filter(a => a.status === ApplicationStatus.REJECTED).length },
  ];

  const handleAppStatus = (id: string, status: ApplicationStatus) => {
    const updatedApps = db.applications.map(a => a.id === id ? { ...a, status } : a);
    const newDb = { ...db, applications: updatedApps };
    setDb(newDb);
    saveDb(newDb);
  };

  const deleteProject = (id: string) => {
    if (!confirm('A jeni të sigurt që dëshironi të fshini këtë projekt?')) return;
    const updatedProjects = db.projects.filter(p => p.id !== id);
    const newDb = { ...db, projects: updatedProjects };
    setDb(newDb);
    saveDb(newDb);
  };

  const deleteNews = (id: string) => {
    if (!confirm('Fshij këtë lajm?')) return;
    const updatedNews = db.news.filter(n => n.id !== id);
    const newDb = { ...db, news: updatedNews };
    setDb(newDb);
    saveDb(newDb);
  };

  const deleteStaff = (id: string) => {
    if (!confirm('Fshij këtë anëtar të stafit?')) return;
    const updatedStaff = db.staff.filter(s => s.id !== id);
    const newDb = { ...db, staff: updatedStaff };
    setDb(newDb);
    saveDb(newDb);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsUploading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewNews(prev => ({ 
          ...prev, 
          fileUrl: reader.result as string,
          fileName: file.name
        }));
        setIsUploading(false);
      };
      reader.readAsDataURL(file);
    }
  };

