import React, { useState, useEffect } from 'react';
import { Search, MapPin, Calendar, Users, Filter, CheckCircle2, Info, ArrowRight } from 'lucide-react';
import { Project, ProjectStatus, User, UserRole, ApplicationStatus } from '../types';
import { getDb, saveDb } from '../services/mockDb';

interface ProjectsProps {
  user: User | null;
}

const Projects: React.FC<ProjectsProps> = ({ user }) => {
  const [projects, setProjects] = useState<Project[]>([]);
  const [filter, setFilter] = useState<string>('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [applyingTo, setApplyingTo] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  useEffect(() => {
    const db = getDb();
    setProjects(db.projects);
  }, []);

  const filteredProjects = projects.filter(p => {
    const matchesFilter = filter === 'All' || p.status === filter;
    const matchesSearch = p.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          p.description.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  const handleApply = (project: Project) => {
    if (!user) {
      window.location.hash = '/login';
      return;
    }

    setApplyingTo(project.id);

    setTimeout(() => {
      const db = getDb();
      const newApp = {
        id: 'app_' + Date.now(),
        userId: user.id,
        userName: user.name,
        userEmail: user.email,
        projectId: project.id,
        projectTitle: project.title,
        status: ApplicationStatus.PENDING,
        dateApplied: new Date().toISOString().split('T')[0]
      };

      db.applications.push(newApp);
      saveDb(db);

      setApplyingTo(null);
      setSuccessMessage(`Aplikimi juaj për "${project.title}" u dërgua me sukses!`);

      setTimeout(() => setSuccessMessage(null), 5000);
    }, 1500);
  };

  return (
    <div className="py-24 px-6 bg-slate-50 min-h-screen">
      <div className="max-w-7xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-12 mb-20">
          <div>
            <span className="text-brand-pink font-bold uppercase tracking-widest text-[10px] mb-4 block">Veprimtaria dhe Ndikimi</span>
            <h1 className="text-5xl md:text-6xl font-black text-brand-dark mb-6 uppercase tracking-tighter leading-none">
              Iniciativat e <span className="text-brand-pink">Shalës</span>
            </h1>
            <p className="text-slate-500 font-medium max-w-xl text-lg leading-relaxed">
              Njihuni me projektet tona që po ndryshojnë jetët e të rinjve në rajon. Çdo projekt është i dizajnuar për zhvillim dhe fuqizim.
            </p>
          </div>

          <div className="flex flex-col sm:flex-row gap-6">
            <div className="relative group">
              <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 h-5 w-5 group-focus-within:text-brand-pink transition-colors" />
              <input 
                type="text" 
                placeholder="Kërko projektin..." 
                className="pl-14 pr-8 py-4 bg-white border border-slate-200 rounded-3xl focus:ring-2 focus:ring-brand-pink outline-none w-full sm:w-80 shadow-sm font-bold transition-all text-sm"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>
        </div>

        <div className="flex items-center space-x-2 mb-12 bg-white/50 p-2 rounded-3xl inline-flex border border-slate-100 shadow-sm">
          {['All', 'Active', 'Completed'].map(f => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              className={`px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${filter === f ? 'bg-brand-dark text-white shadow-xl translate-y-[-2px]' : 'text-slate-400 hover:text-brand-dark hover:bg-slate-50'}`}
            >
              {f === 'All' ? 'Të gjitha' : f === 'Active' ? 'Aktive' : 'Të mbyllura'}
            </button>
          ))}
        </div>

        {successMessage && (
          <div className="mb-12 p-6 bg-white border-l-8 border-brand-lime text-brand-dark rounded-r-[2rem] flex items-center shadow-2xl animate-in slide-in-from-top-4">
            <div className="bg-brand-lime p-3 rounded-2xl mr-6 text-white shadow-lg">
              <CheckCircle2 className="h-6 w-6" />
            </div>
            <div>
              <p className="font-black uppercase text-xs tracking-widest mb-1 text-brand-lime">Sukses!</p>
              <p className="font-bold text-slate-600">{successMessage}</p>
            </div>
          </div>
        )}

        {filteredProjects.length === 0 ? (
          <div className="text-center py-32 bg-white rounded-[3rem] border-2 border-dashed border-slate-200">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-8">
              <Filter className="h-8 w-8 text-slate-300" />
            </div>
            <h3 className="text-2xl font-black text-brand-dark uppercase tracking-tight">Asnjë rezultat</h3>
            <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest mt-2">Provoni terma të tjerë të kërkimit.</p>
          </div>
        ) : (
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-12">
            {filteredProjects.map(project => (
              <div key={project.id} className="bg-white rounded-[3rem] overflow-hidden shadow-sm hover:shadow-2xl transition-all border border-slate-100 flex flex-col group relative hover:-translate-y-2 duration-500">
                <div className="relative h-72 overflow-hidden">
                  <img 
                    src={project.image} 
                    alt={project.title} 
                    className="w-full h-full object-cover grayscale group-hover:grayscale-0 group-hover:scale-110 transition-all duration-1000"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-brand-dark/90 via-brand-dark/20 to-transparent"></div>

                  <div className="absolute top-8 left-8">
                    <span className={`px-5 py-2 rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] shadow-2xl ${
                      project.status === ProjectStatus.ACTIVE ? 'bg-brand-lime text-white' : 'bg-slate-700 text-white'
                    }`}>
                      {project.status === ProjectStatus.ACTIVE ? 'Aktive' : 'Mbyllur'}
                    </span>
                  </div>

                  <div className="absolute bottom-8 left-8 right-8">
                    <h3 className="text-3xl font-black text-white uppercase leading-tight tracking-tighter group-hover:text-brand-pink transition-colors">
                      {project.title}
                    </h3>
                  </div>
                </div>

                <div className="p-10 flex-grow flex flex-col">
                  <div className="flex items-center space-x-3 mb-6 text-brand-pink">
                    <Info className="h-5 w-5" />
                    <span className="text-[10px] font-black uppercase tracking-widest">Detajet e Projektit</span>
                  </div>

                  <p className="text-slate-500 text-sm mb-10 leading-relaxed font-medium line-clamp-4">
                    {project.description}
                  </p>

                  <div className="grid grid-cols-2 gap-6 mb-10 p-6 bg-slate-50 rounded-[2rem] border border-slate-100">
                    <div className="flex flex-col">
                      <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Fillon</span>
                      <span className="text-xs font-bold text-slate-700">{project.startDate}</span>
                    </div>
                    <div className="flex flex-col">
                      <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Mbaron</span>
                      <span className="text-xs font-bold text-slate-700">{project.endDate}</span>
                    </div>
                  </div>

                  <button 
                    disabled={project.status !== ProjectStatus.ACTIVE || applyingTo === project.id}
                    onClick={() => handleApply(project)}
                    className={`mt-auto w-full py-5 rounded-2xl font-black uppercase text-xs tracking-[0.2em] transition-all shadow-xl flex items-center justify-center group/btn ${
                      project.status !== ProjectStatus.ACTIVE 
                        ? 'bg-slate-100 text-slate-400 cursor-not-allowed'
                        : 'bg-brand-dark text-white hover:bg-brand-pink shadow-brand-pink/10 hover:shadow-brand-pink/30'
                    }`}
                  >
                    {applyingTo === project.id ? (
                      <div className="flex items-center">
                        <div className="h-4 w-4 border-2 border-white/30 border-t-white rounded-full animate-spin mr-3"></div>
                        Duke aplikuar...
                      </div>
                    ) : project.status === ProjectStatus.ACTIVE ? (
                      <>
                        Apliko si Vullnetar 
                        <ArrowRight className="ml-3 h-4 w-4 group-hover/btn:translate-x-2 transition-transform" />
                      </>
                    ) : 'Projekti i Mbyllur'}
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

