import React, { useState, useEffect, useRef } from 'react';
import { 
  LayoutDashboard, FolderKanban, Users, 
  Plus, Edit2, Trash2, X, Newspaper, Briefcase, Camera, 
  LayoutList, Facebook, Instagram, Linkedin
} from 'lucide-react';
import { getDb, saveDb } from '../services/mockDb';
import { Project, ApplicationStatus, ProjectStatus, NewsItem, StaffMember, VolunteerApplication } from '../types';

const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'projects' | 'applications' | 'news' | 'staff'>('overview');
  const [db, setDb] = useState(getDb());

  const [showProjectModal, setShowProjectModal] = useState(false);
  const [showNewsModal, setShowNewsModal] = useState(false);
  const [showStaffModal, setShowStaffModal] = useState(false);
  const [showAppModal, setShowAppModal] = useState(false);
  const [selectedApp, setSelectedApp] = useState<VolunteerApplication | null>(null);

  const [editingProject, setEditingProject] = useState<Project | null>(null);
  const [editingNews, setEditingNews] = useState<NewsItem | null>(null);
  const [editingStaff, setEditingStaff] = useState<StaffMember | null>(null);

  const staffImageRef = useRef<HTMLInputElement>(null);

  const [staffForm, setStaffForm] = useState({
    name: '', 
    role: '', 
    category: 'Stafi Aktual', 
    bio: '', 
    image: '', 
    socials: { facebook: '', instagram: '', linkedin: '' }
  });

  const staffCategories = [
    'Kuvendi i Anëtarëve',
    'Bordi i Drejtorëve',
    'Drejtor Ekzekutiv',
    'Stafi Aktual',
    'Vullnetarët'
  ];

  useEffect(() => {
    setDb(getDb());
  }, []);

  const handleFileRead = (file: File): Promise<string> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onloadend = () => resolve(reader.result as string);
      reader.readAsDataURL(file);
    });
  };

  const handleOpenStaffModal = (member?: StaffMember) => {
    if (member) {
      setEditingStaff(member);
      setStaffForm({
        name: member.name,
        role: member.role,
        category: member.category || 'Stafi Aktual',
        bio: member.bio || '',
        image: member.image || '',
        socials: {
          facebook: member.socials?.facebook || '',
          instagram: member.socials?.instagram || '',
          linkedin: member.socials?.linkedin || '',
        }
      });
    } else {
      setEditingStaff(null);
      setStaffForm({ 
        name: '', 
        role: '', 
        category: 'Stafi Aktual', 
        bio: '', 
        image: '', 
        socials: { facebook: '', instagram: '', linkedin: '' } 
      });
    }
    setShowStaffModal(true);
  };

  const handleSaveStaff = () => {
    if (!staffForm.name || !staffForm.role) return alert("Ju lutem plotësoni emrin dhe pozitën.");

    const newStaffMember: StaffMember = {
      id: editingStaff ? editingStaff.id : 's_' + Date.now(),
      name: staffForm.name,
      role: staffForm.role,
      category: staffForm.category,
      bio: staffForm.bio,
      image: staffForm.image || 'https://images.unsplash.com/photo-1550525811-e5869dd03032?auto=format&fit=crop&q=80&w=100',
      socials: staffForm.socials
    };

    const updatedStaff = editingStaff
      ? db.staff.map(s => s.id === editingStaff.id ? newStaffMember : s)
      : [...db.staff, newStaffMember];

    updateDb({ ...db, staff: updatedStaff });
    setShowStaffModal(false);
  };

  const updateDb = (newDb: any) => {
    setDb(newDb);
    saveDb(newDb);
  };

  const deleteItem = (type: 'projects' | 'news' | 'staff', id: string) => {
    if (!confirm('A jeni të sigurt?')) return;
    const newData = { ...db, [type]: db[type].filter((item: any) => item.id !== id) };
    updateDb(newData);
  };

  const stats = [
    { label: 'Projekte', value: db.projects.length, icon: FolderKanban, color: 'bg-brand-pink' },
    { label: 'Aplikime', value: db.applications?.length || 0, icon: Users, color: 'bg-brand-cyan' },
    { label: 'Staff', value: db.staff.length, icon: Briefcase, color: 'bg-brand-blue' },
    { label: 'Lajme', value: db.news.length, icon: Newspaper, color: 'bg-brand-lime' },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      <aside className="w-full md:w-72 bg-brand-dark border-r border-slate-800 flex-shrink-0 text-white z-20">
        <div className="p-8 sticky top-0">
          <div className="flex items-center space-x-3 mb-10">
            <div className="w-8 h-8 rounded-full border-2 border-brand-pink flex items-center justify-center">
              <div className="w-3 h-3 bg-brand-pink rounded-full"></div>
            </div>
            <span className="text-sm font-black uppercase tracking-[0.2em]">ADMIN PANEL</span>
          </div>
          <nav className="space-y-2">
            {[
              { id: 'overview', icon: LayoutDashboard, label: 'Pasqyra' },
              { id: 'projects', icon: FolderKanban, label: 'Projektet' },
              { id: 'staff', icon: Briefcase, label: 'Stafi & Ekipi' },
              { id: 'news', icon: Newspaper, label: 'Lajmet' },
              { id: 'applications', icon: Users, label: 'Aplikimet' },
            ].map(item => (
              <button 
                key={item.id}
                onClick={() => setActiveTab(item.id as any)}
                className={`w-full flex items-center space-x-4 px-6 py-4 rounded-2xl transition-all font-bold uppercase text-[10px] tracking-widest ${activeTab === item.id ? 'bg-white/10 text-brand-pink shadow-lg' : 'text-slate-400 hover:bg-white/5 hover:text-white'}`}
              >
                <item.icon className="h-5 w-5" />
                <span>{item.label}</span>
              </button>
            ))}
          </nav>
        </div>
      </aside>

      <main className="flex-grow p-8 md:p-12">
        <div className="max-w-6xl mx-auto">

          {activeTab === 'overview' && (
            <div className="space-y-12 animate-in fade-in">
              <h1 className="text-4xl font-black text-brand-dark uppercase tracking-tight">Menaxhimi i VRSH</h1>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
                {stats.map((stat, i) => (
                  <div key={i} className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
                    <div className={`${stat.color} w-12 h-12 rounded-2xl text-white flex items-center justify-center mb-6`}>
                      <stat.icon className="h-6 w-6" />
                    </div>
                    <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.15em] mb-1">{stat.label}</p>
                    <p className="text-3xl font-black text-brand-dark">{stat.value}</p>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'staff' && (
            <div className="space-y-8 animate-in fade-in">
              <div className="flex items-center justify-between">
                <h1 className="text-3xl font-black text-brand-dark uppercase">Stafi & Ekipi</h1>
                <button onClick={() => handleOpenStaffModal()} className="bg-brand-cyan text-white px-8 py-3 rounded-full font-black uppercase text-[10px] tracking-widest flex items-center shadow-lg shadow-brand-cyan/20">
                  <Plus className="h-4 w-4 mr-2" /> Shto Person
                </button>
              </div>
              <div className="bg-white rounded-[2rem] border border-slate-100 overflow-hidden shadow-sm">
                <table className="w-full text-left">
                  <thead className="bg-slate-50/50 border-b border-slate-100">
                    <tr>
                      <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Emri</th>
                      <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Kategoria</th>
                      <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pozita</th>
                      <th className="px-8 py-5 text-right">Veprimet</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {db.staff.map(s => (
                      <tr key={s.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-6 flex items-center space-x-3">
                           <img src={s.image} className="w-10 h-10 rounded-full object-cover bg-slate-100" />
                           <span className="font-bold text-sm">{s.name}</span>
                        </td>
                        <td className="px-8 py-6">
                           <span className="text-[10px] font-bold uppercase text-slate-400">{s.category}</span>
                        </td>
                        <td className="px-8 py-6">
                           <span className="text-[10px] font-black uppercase text-brand-pink">{s.role}</span>
                        </td>
                        <td className="px-8 py-6 text-right space-x-2">
                          <button onClick={() => handleOpenStaffModal(s)} className="p-2 text-slate-400 hover:text-brand-pink transition-colors"><Edit2 className="h-4 w-4" /></button>
                          <button onClick={() => deleteItem('staff', s.id)} className="p-2 text-slate-400 hover:text-red-500 transition-colors"><Trash2 className="h-4 w-4" /></button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </main>

      {showStaffModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-brand-dark/60 backdrop-blur-md">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden">
             <div className="p-10 border-b border-slate-100 flex items-center justify-between">
               <h2 className="text-2xl font-black text-brand-dark uppercase">{editingStaff ? 'Edito Personin' : 'Shto Person të Ri'}</h2>
               <button onClick={() => setShowStaffModal(false)}><X className="h-8 w-8 text-slate-300" /></button>
             </div>
             <div className="p-10 space-y-6 max-h-[70vh] overflow-y-auto custom-scrollbar">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Emri Mbiemri</label>
                    <input type="text" className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-brand-cyan outline-none" value={staffForm.name} onChange={e => setStaffForm({...staffForm, name: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Kategoria Organizative</label>
                    <select 
                      className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-brand-cyan outline-none" 
                      value={staffForm.category} 
                      onChange={e => setStaffForm({...staffForm, category: e.target.value})}
                    >
                      {staffCategories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                    </select>
                  </div>
                </div>

                <div className="space-y-2">
                   <label className="text-[10px] font-black uppercase text-slate-400">Pozita / Roli</label>
                   <input 
                      type="text" 
                      placeholder="P.sh. Asistente e Projekteve, Anëtar i Bordit..."
                      className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-brand-cyan outline-none" 
                      value={staffForm.role} 
                      onChange={e => setStaffForm({...staffForm, role: e.target.value})}
                   />
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400">Fotoja</label>
                  <div onClick={() => staffImageRef.current?.click()} className="cursor-pointer h-32 border-2 border-dashed border-slate-200 rounded-2xl flex items-center justify-center overflow-hidden bg-slate-50">
                    {staffForm.image ? <img src={staffForm.image} className="w-full h-full object-cover" /> : <div className="flex flex-col items-center"><Camera className="text-slate-300 mb-1" /><span className="text-[8px] font-black uppercase text-slate-400">Ngarko Foto</span></div>}
                  </div>
                  <input type="file" hidden ref={staffImageRef} accept="image/*" onChange={async e => {
                    const input = e.target as HTMLInputElement;
                    const file = input.files?.[0];
                    if (file) setStaffForm({...staffForm, image: await handleFileRead(file)});
                  }} />
                </div>

                <div className="space-y-2">
                   <label className="text-[10px] font-black uppercase text-slate-400">Bio / Përshkrimi</label>
                   <textarea 
                      rows={3}
                      placeholder="Shkruani një përshkrim të shkurtër për këtë person..."
                      className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-medium focus:ring-2 focus:ring-brand-cyan outline-none resize-none" 
                      value={staffForm.bio} 
                      onChange={e => setStaffForm({...staffForm, bio: e.target.value})}
                   />
                </div>

                <div className="space-y-4 pt-4 border-t border-slate-100">
                   <label className="text-[10px] font-black uppercase text-slate-400">Rrjetet Sociale (Linqet)</label>
                   <div className="grid grid-cols-1 gap-4">
                      <div className="relative">
                        <Facebook className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                        <input type="text" placeholder="Linku i Facebook" className="w-full pl-12 pr-6 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs outline-none focus:ring-2 focus:ring-brand-pink" value={staffForm.socials.facebook} onChange={e => setStaffForm({...staffForm, socials: {...staffForm.socials, facebook: e.target.value}})} />
                      </div>
                      <div className="relative">
                        <Instagram className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                        <input type="text" placeholder="Linku i Instagram" className="w-full pl-12 pr-6 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs outline-none focus:ring-2 focus:ring-brand-pink" value={staffForm.socials.instagram} onChange={e => setStaffForm({...staffForm, socials: {...staffForm.socials, instagram: e.target.value}})} />
                      </div>
                      <div className="relative">
                        <Linkedin className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                        <input type="text" placeholder="Linku i LinkedIn" className="w-full pl-12 pr-6 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs outline-none focus:ring-2 focus:ring-brand-pink" value={staffForm.socials.linkedin} onChange={e => setStaffForm({...staffForm, socials: {...staffForm.socials, linkedin: e.target.value}})} />
                      </div>
                   </div>
                </div>

                <button onClick={handleSaveStaff} className="w-full py-5 bg-brand-cyan text-white rounded-2xl font-black uppercase text-sm tracking-widest shadow-xl shadow-brand-cyan/20">Ruaj Të Dhënat</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { Search, Calendar, Info, ArrowRight, X, Image as ImageIcon, LayoutGrid } from 'lucide-react';
import { Project, ProjectStatus, User } from '../types';
import { getDb } from '../services/mockDb';

interface ProjectsProps {
  user: User | null;
}

const Projects: React.FC<ProjectsProps> = ({ user }) => {
  const [projects, setProjects] = useState<Project[]>([]);
  const [filter, setFilter] = useState<string>('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  useEffect(() => {
    const db = getDb();
    setProjects(db.projects);
  }, []);

  const filteredProjects = projects.filter(p => {
    const matchesFilter = filter === 'All' || p.status === filter;
    const matchesSearch = p.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          p.description.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  return (
    <div className="py-24 px-6 bg-[#f8fafc] min-h-screen">
      <div className="max-w-7xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-12 mb-20">
          <div>
            <span className="text-brand-pink font-black uppercase tracking-[0.5em] text-[10px] mb-4 block">Veprimtaria</span>
            <h1 className="text-6xl md:text-8xl font-black text-brand-dark mb-6 uppercase tracking-tighter leading-[0.85]">
              Projektet e <br/><span className="text-brand-pink">Vizionit</span>
            </h1>
            <p className="text-slate-500 font-medium max-w-xl text-lg leading-relaxed italic">
              Zbuloni iniciativat që po transformojnë rajonin tonë përmes punës, pasionit dhe teknologjisë.
            </p>
          </div>

          <div className="relative group">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300 h-5 w-5 group-focus-within:text-brand-pink transition-colors" />
            <input 
              type="text" 
              placeholder="Kërko projektin..." 
              className="pl-16 pr-8 py-5 bg-white border border-slate-100 rounded-[2rem] focus:ring-2 focus:ring-brand-pink outline-none w-full sm:w-80 shadow-sm font-bold transition-all text-sm text-brand-dark"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="flex items-center space-x-3 mb-16 bg-slate-100/50 p-2 rounded-[2.5rem] inline-flex border border-white shadow-inner">
          {['All', 'Active', 'Completed'].map(f => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              className={`px-10 py-4 rounded-[1.8rem] text-[10px] font-black uppercase tracking-widest transition-all ${filter === f ? 'bg-white text-brand-dark shadow-xl scale-105' : 'text-slate-400 hover:text-brand-dark'}`}
            >
              {f === 'All' ? 'Të gjitha' : f === 'Active' ? 'Aktive' : 'Të mbyllura'}
            </button>
          ))}
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-12">
          {filteredProjects.map(project => (
            <div 
              key={project.id} 
              onClick={() => setSelectedProject(project)}
              className="bg-white rounded-[4rem] overflow-hidden shadow-sm hover:shadow-2xl transition-all border border-white flex flex-col group relative cursor-pointer hover:-translate-y-3 duration-500"
            >
              <div className="relative h-80 overflow-hidden">
                <img 
                  src={project.image} 
                  alt={project.title} 
                  className="w-full h-full object-cover grayscale group-hover:grayscale-0 group-hover:scale-110 transition-all duration-1000"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-brand-dark/40 to-transparent"></div>
                <div className="absolute top-8 left-8">
                  <span className={`px-6 py-2 rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] shadow-2xl ${
                    project.status === ProjectStatus.Active ? 'bg-brand-lime text-white' : 'bg-brand-dark/60 text-white'
                  }`}>
                    {project.status === ProjectStatus.Active ? 'Aktive' : 'Mbyllur'}
                  </span>
                </div>
              </div>
              <div className="p-12 flex-grow flex flex-col">
                <h3 className="text-3xl font-black text-brand-dark uppercase leading-none tracking-tighter group-hover:text-brand-pink transition-colors mb-6">
                  {project.title}
                </h3>
                <p className="text-slate-500 text-sm mb-10 leading-relaxed font-medium line-clamp-3 italic opacity-80">
                  "{project.description}"
                </p>
                <div className="mt-auto flex items-center justify-between pt-8 border-t border-slate-50">
                  <div className="flex items-center text-slate-400">
                    <Calendar className="h-4 w-4 mr-2" />
                    <span className="text-[10px] font-black uppercase tracking-widest">{project.startDate}</span>
                  </div>
                  <div className="flex items-center text-brand-pink font-black text-[10px] uppercase tracking-[0.2em] group-hover:translate-x-2 transition-transform">
                    Shiko më shumë <ArrowRight className="ml-2 h-4 w-4" />
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Project Detail Modal */}
        {selectedProject && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 md:p-12 bg-white/80 backdrop-blur-2xl animate-in fade-in duration-300">
            <div className="bg-white w-full max-w-6xl h-full max-h-[90vh] rounded-[4rem] shadow-[0_40px_100px_rgba(0,0,0,0.1)] overflow-hidden flex flex-col md:flex-row animate-in zoom-in duration-300 border border-white">
              <button 
                onClick={() => setSelectedProject(null)}
                className="absolute top-10 right-10 z-[110] bg-slate-50 text-slate-400 p-4 rounded-full shadow-lg hover:bg-brand-pink hover:text-white transition-all hover:rotate-90 duration-500"
              >
                <X className="h-7 w-7" />
              </button>

              <div className="w-full md:w-1/2 h-64 md:h-full bg-slate-100 overflow-y-auto custom-scrollbar">
                <div className="grid grid-cols-1 gap-0.5">
                  <img src={selectedProject.image} alt={selectedProject.title} className="w-full h-auto" />
                  {selectedProject.gallery?.map((img, i) => (
                    <img key={i} src={img} alt={`Gallery ${i}`} className="w-full h-auto" />
                  ))}
                </div>
              </div>

              <div className="flex-1 p-12 md:p-20 overflow-y-auto flex flex-col">
                <div className="mb-12">
                  <span className="text-brand-pink font-black text-[10px] uppercase tracking-[0.5em] mb-4 block">Detajet e Projektit</span>
                  <h2 className="text-5xl md:text-6xl font-black text-brand-dark uppercase tracking-tighter leading-none mb-6">{selectedProject.title}</h2>
                  <div className="h-2 w-24 bg-brand-pink rounded-full"></div>
                </div>

                <div className="space-y-12 flex-grow">
                   <div>
                      <h4 className="text-[10px] font-black text-slate-300 uppercase tracking-[0.4em] mb-6">Përmbledhja</h4>
                      <p className="text-2xl text-slate-700 font-medium leading-relaxed italic">{selectedProject.description}</p>
                   </div>

                   <div>
                      <h4 className="text-[10px] font-black text-slate-300 uppercase tracking-[0.4em] mb-6">Objektivat & Zbatimi</h4>
                      <div className="text-slate-600 leading-relaxed font-medium text-lg whitespace-pre-wrap">
                        {selectedProject.longDescription || "Informacioni po porditësohet..."}
                      </div>
                   </div>

                   <div className="grid grid-cols-2 gap-12 pt-12 border-t border-slate-100">
                      <div className="flex flex-col">
                        <span className="text-[9px] font-black text-slate-300 uppercase tracking-[0.4em] mb-2">Periudha Kohore</span>
                        <span className="text-lg font-black text-brand-dark">{selectedProject.startDate} — {selectedProject.endDate}</span>
                      </div>
                      <div className="flex flex-col">
                        <span className="text-[9px] font-black text-slate-300 uppercase tracking-[0.4em] mb-2">Bashkëpunëtorë</span>
                        <span className="text-lg font-black text-brand-dark">{selectedProject.volunteerCount} Të angazhuar</span>
                      </div>
                   </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Projects;

import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, LayoutDashboard, LogOut, LogIn, ChevronDown, UserPlus, MessageSquare } from 'lucide-react';
import { User, UserRole } from '../types';

interface NavbarProps {
  user: User | null;
  onLogout: () => void;
}

const VizioniLogo = () => (
  <div className="relative flex items-center justify-center w-11 h-11">
    <div className="absolute inset-0 rounded-full border-4 border-transparent" 
         style={{ borderTopColor: '#e11d74', borderRightColor: '#f39237', borderBottomColor: '#95d03a', borderLeftColor: '#00adb5' }}></div>
    <div className="w-3.5 h-3.5 bg-brand-dark rounded-full"></div>
  </div>
);

const Navbar: React.FC<NavbarProps> = ({ user, onLogout }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [activeDropdown, setActiveDropdown] = useState<string | null>(null);
  const location = useLocation();

  const isActive = (path: string) => location.pathname === path || (path !== '/' && location.pathname.startsWith(path));

  return (
    <nav className="bg-white/90 backdrop-blur-xl border-b border-slate-100 sticky top-0 z-[150] shadow-sm">
      <div className="max-w-7xl mx-auto px-6 lg:px-8">
        <div className="flex justify-between h-20">
          <div className="flex items-center">
            <Link to="/" className="flex items-center space-x-4 group">
              <VizioniLogo />
              <div className="flex flex-col -space-y-1">
                <span className="text-2xl font-black text-brand-dark tracking-tighter leading-none uppercase group-hover:text-brand-pink transition-colors">Vizioni</span>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.25em]">Rinor i Shales</span>
              </div>
            </Link>
          </div>

          {/* Desktop Menu */}
          <div className="hidden md:flex items-center space-x-10">
            <Link to="/" className={`text-[11px] font-black uppercase tracking-[0.2em] transition-colors ${location.pathname === '/' ? 'text-brand-pink' : 'text-slate-500 hover:text-brand-dark'}`}>
              Kreu
            </Link>

            <div className="relative group" onMouseEnter={() => setActiveDropdown('about')} onMouseLeave={() => setActiveDropdown(null)}>
              <button className={`flex items-center space-x-2 text-[11px] font-black uppercase tracking-[0.2em] transition-colors ${isActive('/about') ? 'text-brand-pink' : 'text-slate-500 hover:text-brand-dark'}`}>
                <span>Rreth Nesh</span>
                <ChevronDown className="h-3 w-3" />
              </button>
              <div className={`absolute left-0 mt-2 w-56 bg-white border border-slate-100 shadow-[0_20px_50px_rgba(0,0,0,0.1)] rounded-[2rem] py-4 transition-all transform origin-top ${activeDropdown === 'about' ? 'opacity-100 scale-100' : 'opacity-0 scale-95 pointer-events-none'}`}>
                <Link to="/about/mission" className="block px-8 py-3 text-[10px] font-black text-slate-500 hover:bg-slate-50 hover:text-brand-pink uppercase tracking-widest">Misioni</Link>
                <Link to="/about/staff" className="block px-8 py-3 text-[10px] font-black text-slate-500 hover:bg-slate-50 hover:text-brand-pink uppercase tracking-widest">Ekipi</Link>
              </div>
            </div>

            <Link to="/projects" className={`text-[11px] font-black uppercase tracking-[0.2em] transition-colors ${isActive('/projects') ? 'text-brand-pink' : 'text-slate-500 hover:text-brand-dark'}`}>
              Projekte
            </Link>

            <Link to="/derdo" className={`flex items-center space-x-2 text-[11px] font-black uppercase tracking-[0.2em] transition-colors ${isActive('/derdo') ? 'text-brand-orange' : 'text-slate-500 hover:text-brand-orange'}`}>
              <MessageSquare className="h-4 w-4" />
              <span>Derdo AI</span>
            </Link>

            <Link to="/join" className={`flex items-center space-x-2 px-8 py-3 rounded-full text-[10px] font-black uppercase tracking-[0.2em] transition-all border-2 ${isActive('/join') ? 'bg-brand-lime border-brand-lime text-white' : 'border-brand-lime text-brand-lime hover:bg-brand-lime hover:text-white shadow-lg shadow-brand-lime/10'}`}>
              <UserPlus className="h-4 w-4" />
              <span>Bashkohu</span>
            </Link>

            {user?.role === UserRole.ADMIN && (
              <Link to="/admin" className="flex items-center space-x-2 text-[11px] font-black uppercase tracking-widest text-brand-cyan hover:opacity-80 transition-colors">
                <LayoutDashboard className="h-4 w-4" />
                <span>Admin</span>
              </Link>
            )}

            {user ? (
              <button onClick={onLogout} className="p-3 text-slate-300 hover:text-red-500 transition-colors"><LogOut className="h-6 w-6" /></button>
            ) : (
              <Link to="/login" className="flex items-center space-x-2 bg-brand-dark text-white px-8 py-3 rounded-full text-[10px] font-black uppercase tracking-[0.2em] hover:bg-brand-pink shadow-xl transition-all">
                <LogIn className="h-4 w-4" />
                <span>Kyçu</span>
              </Link>
            )}
          </div>

          <div className="md:hidden flex items-center">
            <button onClick={() => setIsOpen(!isOpen)} className="text-brand-dark p-2 bg-slate-100 rounded-xl"><Menu className="h-6 w-6" /></button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-white border-t border-slate-100 p-8 space-y-6 animate-in slide-in-from-top-4">
           <Link onClick={() => setIsOpen(false)} to="/" className="block text-sm font-black uppercase tracking-widest text-brand-dark">Kreu</Link>
           <Link onClick={() => setIsOpen(false)} to="/about/mission" className="block text-sm font-black uppercase tracking-widest text-brand-dark">Misioni</Link>
           <Link onClick={() => setIsOpen(false)} to="/about/staff" className="block text-sm font-black uppercase tracking-widest text-brand-dark">Ekipi</Link>
           <Link onClick={() => setIsOpen(false)} to="/projects" className="block text-sm font-black uppercase tracking-widest text-brand-dark">Projekte</Link>
           <Link onClick={() => setIsOpen(false)} to="/derdo" className="block text-sm font-black uppercase tracking-widest text-brand-orange">Derdo AI</Link>
           <Link onClick={() => setIsOpen(false)} to="/join" className="block text-sm font-black uppercase tracking-widest text-brand-lime">Bashkohu</Link>
           {!user && <Link onClick={() => setIsOpen(false)} to="/login" className="block text-sm font-black uppercase tracking-widest text-brand-pink">Kyçu</Link>}
        </div>
      )}
    </nav>
  );
};

export default Navbar;
